import React from "react";
import styleMesseg from "./Messeg.module.scss";
import { createUseStyles } from "react-jss";

const useStyles = createUseStyles({
  container: {
    color: "var(--white)",
    width: "fit-content",
    wordBreak: "break-all",
    listStyle: "none",
    nick_20: {
      backgroundColor: "red",
    },
  },
});

const Messeg = ({ text, id, Created_At }) => {
  const classes = useStyles();
  const hi = () => alert(text);

  return (
    <div onClick={hi} className={classes.container}>
      <li id={`nick_${id}`} className={styleMesseg.container__list_messeg}>
        <p>{text}</p>
        <p className={styleMesseg.nickName}>{id}</p>
        <p className={styleMesseg.date}>06. 01. 2022</p>
      </li>
    </div>
  );
};

export default Messeg;
